import { useCallback, useEffect, useMemo, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { getSales, getSalesStats, deleteSale } from "../../api/saleApi";
import { getAuth } from "../../utils/auth";

export default function SaleList() {
  const [sales, setSales] = useState([]);
  const [stats, setStats] = useState(null);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // ✅ filter for list display
  const [filter, setFilter] = useState("all"); // all | completed | pending | partial

  const navigate = useNavigate();
  const { role } = getAuth();
  const canManage = role === "admin" || role === "manager";
  const year = new Date().getFullYear();

  const load = useCallback(async () => {
    setError("");
    setLoading(true);

    try {
      const salesRes = await getSales();
      setSales(salesRes.data || []);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to load sales");
      setSales([]);
    } finally {
      setLoading(false);
    }

    // stats optional
    try {
      const statsRes = await getSalesStats(year);
      setStats(statsRes.data || null);
    } catch {
      setStats(null);
    }
  }, [year]);

  useEffect(() => {
    load();
  }, [load]);

  // ✅ Completed means payment_status === "completed"
  const completedOnly = useMemo(
    () => sales.filter((s) => (s.payment_status || "").toLowerCase() === "completed"),
    [sales]
  );

  // ✅ fallback stats if stats API fails
  const totalsFromList = useMemo(() => {
    const totalRevenue = completedOnly.reduce((sum, s) => sum + Number(s.price || 0), 0);

    const months = new Set();
    completedOnly.forEach((s) => {
      const d = new Date(s.createdAt);
      months.add(`${d.getFullYear()}-${d.getMonth() + 1}`);
    });

    const avgMonthlyRevenue = months.size ? totalRevenue / months.size : 0;

    return {
      totalRevenue,
      avgMonthlyRevenue,
      totalSales: completedOnly.length,
    };
  }, [completedOnly]);

  const totalRevenue = stats?.totalRevenue ?? totalsFromList.totalRevenue;
  const avgMonthlyRevenue = stats?.avgMonthlyRevenue ?? totalsFromList.avgMonthlyRevenue;
  const totalSales = stats?.totalSales ?? totalsFromList.totalSales;

  // ✅ Filtered list for UI
  const filteredSales = useMemo(() => {
    if (filter === "all") return sales;
    return sales.filter((s) => (s.payment_status || "").toLowerCase() === filter);
  }, [sales, filter]);

  const onDelete = async (id) => {
    if (!canManage) return alert("Access denied");
    if (!window.confirm("Delete this sale record?")) return;

    try {
      await deleteSale(id);
      alert("Deleted");
      load();
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const statusBadge = (status) => {
    const s = (status || "").toLowerCase();
    const base = {
      display: "inline-block",
      padding: "4px 10px",
      borderRadius: 999,
      fontSize: 12,
      fontWeight: 700,
      border: "1px solid #ccc",
    };

    if (s === "completed") return { ...base, borderColor: "#16a34a", color: "#16a34a" };
    if (s === "partial") return { ...base, borderColor: "#f59e0b", color: "#f59e0b" };
    if (s === "pending") return { ...base, borderColor: "#ef4444", color: "#ef4444" };
    return base;
  };

  return (
    <div style={{ padding: 20 }}>
      {/* Header */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <h2 style={{ margin: 0 }}>Sales</h2>

        <div style={{ display: "flex", gap: 10 }}>
          <button onClick={load} disabled={loading}>
            {loading ? "Loading..." : "Refresh"}
          </button>

          {canManage && (
            <Link to="/sales/add">
              <button>+ Add Sale</button>
            </Link>
          )}
        </div>
      </div>

      {error && (
        <div style={{ marginTop: 12, padding: 10, border: "1px solid #fca5a5", borderRadius: 8 }}>
          <b>Error:</b> {error}
        </div>
      )}

      {/* ✅ Stats only (Completed only) */}
      <div style={{ marginTop: 14, border: "1px solid #ddd", borderRadius: 10, padding: 14 }}>
        <div style={{ display: "flex", gap: 20, flexWrap: "wrap" }}>
          <div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Total Revenue ({year})</div>
            <div style={{ fontSize: 22, fontWeight: 700 }}>
              Rs. {Number(totalRevenue || 0).toLocaleString()}
            </div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Completed only</div>
          </div>

          <div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Monthly Average Revenue</div>
            <div style={{ fontSize: 22, fontWeight: 700 }}>
              Rs. {Number(avgMonthlyRevenue || 0).toLocaleString()}
            </div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Completed only</div>
          </div>

          <div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Completed Sales Count</div>
            <div style={{ fontSize: 22, fontWeight: 700 }}>
              {Number(totalSales || 0)}
            </div>
          </div>
        </div>
      </div>

      {/* ✅ Filter */}
      <div style={{ marginTop: 14, display: "flex", gap: 10, alignItems: "center" }}>
        <b>Show:</b>
        <select value={filter} onChange={(e) => setFilter(e.target.value)} style={{ padding: 8 }}>
          <option value="all">All Sales</option>
          <option value="completed">Completed</option>
          <option value="partial">Partial</option>
          <option value="pending">Pending</option>
        </select>
        <div style={{ fontSize: 12, opacity: 0.7 }}>
          Showing {filteredSales.length} of {sales.length}
        </div>
      </div>

      {/* ✅ List */}
      <table border="1" cellPadding="10" style={{ width: "100%", marginTop: 14, textAlign: "left" }}>
        <thead>
          <tr>
            <th>Vehicle</th>
            <th>Customer (Lead)</th>
            <th>Price</th>
            <th>Payment Status</th>
            <th>Date</th>
            <th style={{ width: 220 }}>Actions</th>
          </tr>
        </thead>

        <tbody>
          {loading && (
            <tr>
              <td colSpan="6">Loading...</td>
            </tr>
          )}

          {!loading &&
            filteredSales.map((s) => (
              <tr key={s._id}>
                <td>
                  {s.vehicle?.brand
                    ? `${s.vehicle.brand} ${s.vehicle.model || s.vehicle.type || ""}`
                    : "-"}
                </td>

                <td>{s.customer?.name || "-"}</td>

                <td>Rs. {Number(s.price || 0).toLocaleString()}</td>

                <td>
                  <span style={statusBadge(s.payment_status)}>{s.payment_status || "-"}</span>
                </td>

                <td>{s.createdAt ? new Date(s.createdAt).toLocaleDateString() : "-"}</td>

                <td>
                  {canManage ? (
                    <>
                      <button onClick={() => navigate(`/sales/edit/${s._id}`)}>
                        Edit
                      </button>
                      <button style={{ marginLeft: 6 }} onClick={() => onDelete(s._id)}>
                        Delete
                      </button>
                    </>
                  ) : (
                    "-"
                  )}
                </td>
              </tr>
            ))}

          {!loading && filteredSales.length === 0 && (
            <tr>
              <td colSpan="6">No sales found</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}
